// GlobResult struct - matches C layout for FFI
// Memory is allocated by C++ and must be freed via aria_glob_free()
pub struct GlobResult {
    wild int8**:paths;   // Array of null-terminated path strings (wild memory)
    int64:count;         // Number of paths in array
    int32:error_code;    // 0 = OK, >0 = error (see GlobError enum)
}

// GlobOptions struct - matches C layout for FFI
pub struct GlobOptions {
    int32:case_sensitive;        // 1 = case sensitive, 0 = case insensitive
    int32:follow_symlinks;       // 1 = follow symlinks, 0 = don't follow
    int64:max_depth;             // 0 = unlimited, >0 = limit
    int32:files_only;            // 1 = only files, 0 = include directories
    int32:directories_only;      // 1 = only directories, 0 = include files
    int32:include_hidden;        // 1 = include dotfiles, 0 = skip
    int32:skip_permission_errors; // 1 = skip, 0 = fail on permission denied
}

