// Aria Standard Library - File System Module
// File: lib/std/fs.aria
//
// This module provides safe file system operations built on the runtime foundation.
// It wraps C++ runtime functions with proper memory management and error handling.
//
// Design Philosophy:
// - Result-based error handling with full error propagation
// - Dual API: Managed (GC) and Wild (zero-copy) variants
// - Clean, high-level API for common file operations
//
// ARIA-018: Standard Library Wrapper Pattern Design
// - Acquire-Convert-Release (ACR) pattern for FFI bridging
// - readFile: Managed API - copies to GC heap, safe for general use
// - readFileWild: Zero-copy API - returns wild buffer, user must free
//
// Reference: docs/gemini/responses/remaining/Standard Library Wrapper Pattern Design.txt

// ============================================================================
// Module Imports
// ============================================================================

use std.internal.runtime;
use std.mem;

// ============================================================================
// External Declarations - C Runtime Bindings
// ============================================================================

extern "aria_runtime" {
    // Simple file operations (abort on error, return managed types)
    // DEPRECATED: Use readFile/readFileWild for proper error handling

    // Read entire file to string
    // Returns empty string on error (length == 0)
    func:aria_read_file_simple = string(int8*:path);

    // Write string to file
    // Returns 0 on success, -1 on error
    func:aria_write_file_simple = int64(int8*:path, int8*:content);

    // Delete file
    // Returns 0 on success, -1 on error
    func:aria_delete_file_simple = int64(int8*:path);

    // Check if file exists
    func:aria_file_exists = bool(int8*:path);

    // Path operations
    func:aria_path_absolute_string = string(int8*:path);
    func:aria_path_dirname_string = string(int8*:path);
    func:aria_path_basename_string = string(int8*:path);
    func:aria_path_join_string = string(int8*:dir, int8*:name);
}

// ============================================================================
// ARIA-018: ACR Pattern File I/O APIs
// ============================================================================

/**
 * Read file contents into a managed GC string
 *
 * This is the high-level, ergonomic API for file reading.
 * It copies the file data from the runtime's wild buffer into the GC heap.
 *
 * ACR Pattern:
 * 1. Acquire: Call runtime.aria_read_file()
 * 2. Convert: Copy data from wild to GC, convert error to string
 * 3. Release: Free the AriaResult and wild buffer
 *
 * Performance Note:
 * - Allocates memory twice (runtime + GC)
 * - Performs memcpy of entire file
 * - Use readFileWild() for large files or performance-critical code
 *
 * Example:
 *   result<string>:res = fs.readFile("config.json");
 *   if (res.is_ok()) {
 *       string:content = res.unwrap();
 *       println(content);
 *   } else {
 *       eprintln("Error: " + res.unwrap_err());
 *   }
 *
 * @param path Path to file (GC string)
 * @return result<string> with file contents or error message
 */
pub func:readFile = result<string>(string:path) {
    // Input Marshaling - convert Aria string to C string
    wild int8*:c_path = runtime.string_to_cstr(path);
    if (c_path == null) {
        fail("Failed to allocate path buffer");
    }

    // CRITICAL: Free the C string when we exit this scope
    defer runtime.aria_free(c_path);

    // Phase 1: Acquire - Call runtime function
    wild runtime.AriaResult*:res = runtime.aria_read_file(c_path);
    if (res == null) {
        fail("Runtime returned null result");
    }

    // Phase 2: Convert - Check for errors
    if (res.err != null) {
        // Error occurred - convert C error string to managed string
        string:err_msg = runtime.string_from_cstr(res.err);

        // Phase 3: Release - Free the result (frees err string too)
        runtime.aria_result_free(res);

        // Return failure
        fail(err_msg);
    }

    // Success path - copy data to GC heap
    uint64:len = res.val_size;

    // Allocate GC string
    string:content = string.allocate(len);

    // Copy from wild buffer to GC string
    unsafe {
        runtime.memcpy(#content.data, res.val, len);
    }

    // Phase 3: Release - Free the AriaResult (and wild buffer)
    runtime.aria_result_free(res);

    // Return managed string
    pass(content);
};

/**
 * Read file contents into a zero-copy WildBuffer
 *
 * This is the high-performance API for systems programming.
 * It "steals" the pointer from the runtime, avoiding a copy.
 *
 * ACR Pattern with Pointer Stealing:
 * 1. Acquire: Call runtime.aria_read_file()
 * 2. Convert: Extract pointer, NULL it in AriaResult
 * 3. Release: Free AriaResult (but not the stolen pointer)
 *
 * MEMORY CONTRACT:
 * - The CALLER owns the returned buffer
 * - The CALLER MUST call mem.free(buf.ptr) when done
 * - Use 'defer' for automatic cleanup
 *
 * Performance Benefits:
 * - Single allocation (runtime only)
 * - Zero memcpy of file data
 * - Suitable for large files (GB+)
 *
 * TBB Integration:
 * - buf.len is tbb64 for arithmetic overflow protection
 * - Size calculations that overflow become ERR sentinel
 *
 * Example:
 *   result<mem.WildBuffer>:res = fs.readFileWild("/var/log/syslog");
 *   if (res.is_ok()) {
 *       mem.WildBuffer:buf = res.unwrap();
 *       defer mem.free(buf.ptr);  // CRITICAL: Must free!
 *
 *       // Process without copy
 *       process_log_data(buf.ptr, buf.len);
 *   }
 *
 * @param path Path to file (GC string)
 * @return result<WildBuffer> with file data or error message
 */
pub func:readFileWild = result<mem.WildBuffer>(string:path) {
    // Input Marshaling
    wild int8*:c_path = runtime.string_to_cstr(path);
    if (c_path == null) {
        fail("Failed to allocate path buffer");
    }
    defer runtime.aria_free(c_path);

    // Phase 1: Acquire
    wild runtime.AriaResult*:res = runtime.aria_read_file(c_path);
    if (res == null) {
        fail("Runtime returned null result");
    }

    // Phase 2: Convert - Check for errors
    if (res.err != null) {
        string:err_msg = runtime.string_from_cstr(res.err);
        runtime.aria_result_free(res);
        fail(err_msg);
    }

    // Zero-Copy Transfer (The Heist)
    // We steal the pointer - O(1) operation
    mem.WildBuffer:buf;
    buf.ptr = res.val;
    buf.len = res.val_size;  // Cast to tbb64 for safety

    // Selective Release (The Trick)
    // NULL out the pointer so aria_result_free doesn't free our data
    res.val = null;

    // Free the AriaResult struct (but not our data!)
    runtime.aria_result_free(res);

    // Return the zero-copy buffer
    pass(buf);
};

/**
 * Write file contents from a managed string
 *
 * Result-based wrapper for file writing with proper error propagation.
 *
 * Example:
 *   result<void>:res = fs.writeFile("output.txt", "Hello, world!");
 *   if (res.is_err()) {
 *       eprintln("Write failed: " + res.unwrap_err());
 *   }
 *
 * @param path Path to file
 * @param content Content to write
 * @return result<void> with success or error
 */
pub func:writeFile = result<void>(string:path, string:content) {
    // Convert to C strings
    wild int8*:c_path = runtime.string_to_cstr(path);
    if (c_path == null) {
        fail("Failed to allocate path buffer");
    }
    defer runtime.aria_free(c_path);

    wild int8*:c_content = runtime.string_to_cstr(content);
    if (c_content == null) {
        fail("Failed to allocate content buffer");
    }
    defer runtime.aria_free(c_content);

    // Call runtime
    wild runtime.AriaResult*:res = runtime.aria_write_file(c_path, c_content);
    if (res == null) {
        fail("Runtime returned null result");
    }

    // Check for errors
    if (res.err != null) {
        string:err_msg = runtime.string_from_cstr(res.err);
        runtime.aria_result_free(res);
        fail(err_msg);
    }

    // Success
    runtime.aria_result_free(res);
    pass();
};

