// ============================================================================
// High-Level Safe Wrapper API
// ============================================================================
// These functions handle memory management automatically, converting
// between wild C pointers and managed Aria strings.

/**
 * Expand a glob pattern and return matching file paths.
 *
 * This is the primary entry point for glob matching. Results are
 * deterministically sorted for reproducible builds.
 *
 * Example:
 *   result<array<string>>:files = fs.glob("src/**/*.aria", ".");
 *   if (files.is_ok()) {
 *       array<string>:paths = files.unwrap();
 *       for (path in paths) {
 *           println(path);
 *       }
 *   }
 *
 * @param pattern Glob pattern (*, **, ?, [abc])
 * @param base_dir Base directory for matching (default: ".")
 * @return Array of matching paths, or error
 */
pub func:glob = result<array<string>>(string:pattern, string:base_dir) {
    // Convert Aria strings to C strings
    wild int8*:c_pattern = pattern.data;
    wild int8*:c_base = base_dir.data;

    // Call FFI function
    GlobResult:res = aria_glob_match(c_base, c_pattern);

    // Ensure cleanup of FFI result (even on error path)
    defer aria_glob_free(@res);

    // Check for errors
    if (res.error_code != 0) {
        fail(ERR);
    }

    // Convert to managed Aria array
    array<string>:matches = array_new<string>(res.count);

    // Copy each path from wild memory to managed memory
    int64:i = 0i64;
    while (i < res.count) {
        wild int8*:path_cstr = res.paths[i];
        string:path = string_from_cstr(path_cstr);
        array_push(@matches, path);
        i = i + 1;
    }

    pass(matches);
};

/**
 * Expand a glob pattern with default base directory.
 * Convenience wrapper that uses current directory as base.
 *
 * Example:
 *   result<array<string>>:files = fs.glob_here("*.aria");
 */
pub func:glob_here = result<array<string>>(string:pattern) {
    pass(glob(pattern, "."));
};

/**
 * Expand multiple glob patterns (logical OR).
 * Results are combined, sorted, and deduplicated.
 *
 * Example:
 *   array<string>:patterns = ["src/**/*.aria", "tests/**/*.aria"];
 *   result<array<string>>:files = fs.glob_all(patterns, ".");
 */
pub func:glob_all = result<array<string>>(array<string>:patterns, string:base_dir) {
    wild int8*:c_base = base_dir.data;

    // Convert pattern array to C array
    int64:count = patterns.length();
    wild int8**:c_patterns = alloc<int8*>(count);
    if (c_patterns == NULL) {
        fail(ERR);
    }
    defer free<int8*>(c_patterns);

    // Copy pattern pointers
    int64:i = 0i64;
    while (i < count) {
        c_patterns[i] = patterns[i].data;
        i = i + 1;
    }

    // Call FFI
    GlobResult:res = aria_glob_match_all(c_base, c_patterns, count);
    defer aria_glob_free(@res);

    if (res.error_code != 0) {
        fail(ERR);
    }

    // Convert to managed array
    array<string>:matches = array_new<string>(res.count);

    i = 0;
    while (i < res.count) {
        wild int8*:path_cstr = res.paths[i];
        string:path = string_from_cstr(path_cstr);
        array_push(@matches, path);
        i = i + 1;
    }

    pass(matches);
};

/**
 * Check if a path matches a glob pattern (without directory traversal).
 *
 * Example:
 *   if (fs.matches("src/main.aria", "**/*.aria")) {
 *       println("Match!");
 *   }
 */
pub func:matches = bool(string:path, string:pattern) {
    wild int8*:c_path = path.data;
    wild int8*:c_pattern = pattern.data;

    int32:result = aria_glob_path_matches(c_path, c_pattern, 1);

    return result == 1;
};

/**
 * Validate a glob pattern syntax.
 *
 * Example:
 *   if (!fs.glob_valid("[unclosed")) {
 *       eprintln("Invalid pattern!");
 *   }
 */
pub func:glob_valid = bool(string:pattern) {
    wild int8*:c_pattern = pattern.data;

    int32:result = aria_glob_validate_pattern(c_pattern);

    return result == 1;
};

