/// Handle to a spawned task
pub struct TaskHandle<T> {
    int32:task_id;
    wild Task@:task;
    T:result;
    bool:completed;
}

/// Await a task handle (get the result when ready)
pub func:await_task<T> = T(TaskHandle<T>:handle) {
    if (handle.completed) {
        pass(handle.result);
    }

    // Poll until complete
    // This is called from within an async context
    while (handle.task != NULL && handle.task->frame->state != CoroState.COMPLETE) {
        @yield_current();  // Suspend current coroutine
    }

    pass(handle.result);
};

