/// TBB-aware future that propagates sticky errors
pub struct TbbFuture<T> {
    Future<tbb64>:inner;
}

impl Future<tbb64> for TbbFuture<tbb64> {
    func:poll = Poll<tbb64>(Context@:ctx) {
        Poll<tbb64>:p = self.inner.poll(ctx);

        if (p.state == PollState.READY) {
            // Check for TBB error sentinel
            if (p.value == math.TBB64_ERR) {
                pass(poll_error<tbb64>(-128));
            }
        }

        pass(p);
    };
}

