func:gcd_i32 = int32(int32:a, int32:b) {
int32:zero = 0i32;
    int32:temp_a = a;
    int32:temp_b = b;

    if (temp_a < zero) {
        temp_a = zero - temp_a;
    } else {}

    if (temp_b < zero) {
        temp_b = zero - temp_b;
    } else {}

    while (temp_b != zero) {
        int32:remainder = temp_a - ((temp_a / temp_b) * temp_b);
        temp_a = temp_b;
        temp_b = remainder;
    }

    return temp_a;
};
}
