// Pipe Type
// ============================================================================

// Pipe handle for inter-process communication
pub struct Pipe {
    wild void*:handle;   // Opaque handle to AriaPipe
    bool:is_valid;       // Whether pipe is valid
}

// Create a new pipe for communication
// Uses pipe2() with O_CLOEXEC for thread safety
pub func:pipe_create = result<Pipe>() {
    wild void*:handle = aria_pipe_create();

    if (handle == null) {
        fail(ERR);
    }

    Pipe:p = {
        handle: handle,
        is_valid: true
    };

    pass(p);
};

// Write data to pipe
pub func:pipe_write = result<int64>(Pipe@:p, string:data) {
    if (!p->is_valid) {
        fail(ERR);
    }

    wild int8*:buf = data.data;
    int64:len = data.length();

    int64:written = aria_pipe_write(p->handle, buf, len);

