func:gcd_i32 = int32(int32:a, int32:b) {
int32:x = a;
    int32:y = b;
    bool:done = false;

    // Handle negatives
    bool:x_neg = (x < 0);
    if (x_neg) {
        x = (0 - x);
    } else {}

    bool:y_neg = (y < 0);
    if (y_neg) {
        y = (0 - y);
    } else {}

    // Euclidean algorithm using while loop
    while (y != 0) {
        int32:temp = y;
        int32:remainder = (x - ((x / y) * y));  // Manual modulo
        y = remainder;
        x = temp;
    }

    pass(x);
};
