/// Extract digit at specific position (0 = ones, 1 = tens, etc.)
func:digit_at = int32(int32:n, int32:pos) {
    int32:val = n;
    int32:i = 0i32;

    // Handle negative
    bool:negative = (val < 0i32);
    if (negative) {
        val = (0i32 - val);
    } else {}

    // Divide by 10^pos
    while (i < pos) {
        val = (val / 10i32);
        i = (i + 1i32);
    }

    // Get last digit
    int32:digit = (val - ((val / 10i32) * 10i32));
    pass(digit);
};

/// Count number of digits
func:count_digits = int32(int32:n) {
    int32:val = n;
    int32:count = 1i32;

    // Handle negative
    bool:negative = (val < 0i32);
    if (negative) {
        val = (0i32 - val);
    } else {}

    // Handle zero
    bool:is_zero = (val == 0i32);
    if (is_zero) {
        count = 1i32;
    } else {
        count = 0i32;
        while (val > 0i32) {
            val = (val / 10i32);
            count = (count + 1i32);
        }
    }

    pass(count);
};

/// Print integer (positive only for now)
func:print_int = NIL(int32:n) {
    bool:is_zero = (n == 0i32);

    if (is_zero) {
        int32:zero = 0i32;
        print_digit(zero) ? NIL;
    } else {
        int32:num_digits = count_digits(n);
        int32:pos = (num_digits - 1i32);

        while (pos >= 0i32) {
            int32:digit = digit_at(n, pos);
            print_digit(digit) ? NIL;
            pos = (pos - 1i32);
        }
