/// Core collection data structures
//!
//! This module provides essential collection types for storing and manipulating
//! groups of values. All collections use generics for type safety and support
//! the Aria memory model with opt-out GC via the wild keyword.

use std.mem;

// ============================================================================
// Vec<T> - Dynamic Array
// ============================================================================

/// A growable, heap-allocated array
/// 
/// Vec provides O(1) indexed access and amortized O(1) push/pop operations.
/// Memory is managed automatically unless using wild allocation.
///
/// @example
/// ```aria
/// // Create empty vector
/// Vec<int32>:numbers = Vec::new();
/// numbers.push(10);
/// numbers.push(20);
/// numbers.push(30);
/// 
/// // Access elements
/// int32:first = numbers.get(0) ? 0;  // 10
/// int32:len = numbers.len();          // 3
/// 
/// // Iterate
/// loop(0, numbers.len(), 1) {
///     int32:val = numbers.get($) ? 0;
///     stdout.write(`Value: &{val}\n`);
/// }
/// ```
pub struct Vec<T> {
    wild *T@:data;      // Pointer to heap data
    uint64:length;      // Number of elements
    uint64:capacity;    // Allocated capacity
}

/// Create a new empty vector
/// @return A new Vec with zero capacity
pub func<T>:vec_new = Vec<*T>() {
    Vec<*T>:v = {
        data: NULL,
        length: 0,
        capacity: 0
    };
    pass(v);
};

/// Create a vector with specified capacity
/// @param cap Initial capacity to allocate
/// @return A new Vec with pre-allocated space
pub func<T>:vec_with_capacity = Vec<*T>(uint64:cap) {
    wild *T@:ptr = aria.alloc<*T>(cap);
    Vec<*T>:v = {
        data: ptr,
        length: 0,
        capacity: cap
    };
    pass(v);
};

/// Add an element to the end of the vector
/// @param vec The vector to push to
/// @param value The value to add
/// @return Result indicating success or allocation failure
pub func<T>:vec_push = result(Vec<*T>@:vec, *T:value) {
    // Check if we need to grow
    if (vec->length >= vec->capacity) {
        // Double capacity (or start at 4)
        uint64:new_cap = is vec->capacity == 0 : 4 : vec->capacity * 2;

        // Allocate new buffer
        wild *T@:new_data = aria.alloc<*T>(new_cap);
        if (new_data == NULL) {
            fail(ERR);  // Allocation failed
        }

        // Copy existing elements
        loop(0, vec->length, 1) {
            new_data[$] = vec->data[$];
        }

        // Free old buffer if it exists
        if (vec->data != NULL) {
            aria.free(vec->data);
        }

        // Update vector
        vec->data = new_data;
        vec->capacity = new_cap;
    }

    // Add element
    vec->data[vec->length] = value;
    vec->length = vec->length + 1;

    pass(NIL);
};

/// Remove and return the last element
/// @param vec The vector to pop from
/// @return The popped value, or ERR if empty
pub func<T>:vec_pop = result<*T>(Vec<*T>@:vec) {
    if (vec->length == 0) {
        fail(ERR);  // Empty vector
    }

    vec->length = vec->length - 1;
    *T:value = vec->data[vec->length];
    pass(value);
};

/// Get element at index
/// @param vec The vector to access
/// @param index The index to retrieve
/// @return The element value, or ERR if out of bounds
pub func<T>:vec_get = result<*T>(Vec<*T>@:vec, uint64:index) {
    if (index >= vec->length) {
        fail(ERR);  // Out of bounds
    }
    pass(vec->data[index]);
};

/// Set element at index
/// @param vec The vector to modify
/// @param index The index to set
/// @param value The new value
/// @return Result indicating success or out of bounds
pub func<T>:vec_set = result(Vec<*T>@:vec, uint64:index, *T:value) {
    if (index >= vec->length) {
        fail(ERR);  // Out of bounds
    }
    vec->data[index] = value;
    pass(NIL);
};

/// Get the number of elements in the vector
/// @param vec The vector to query
/// @return The number of elements
pub func<T>:vec_len = uint64(Vec<*T>@:vec) {
    pass(vec->length);
};

/// Get the allocated capacity
/// @param vec The vector to query
/// @return The capacity
pub func<T>:vec_capacity = uint64(Vec<*T>@:vec) {
    pass(vec->capacity);
};

/// Check if vector is empty
/// @param vec The vector to check
/// @return true if empty, false otherwise
pub func<T>:vec_is_empty = bool(Vec<*T>@:vec) {
    pass(vec->length == 0);
};

/// Remove all elements from the vector
/// @param vec The vector to clear
pub func<T>:vec_clear = result(Vec<*T>@:vec) {
    vec->length = 0;
    pass(NIL);
};

/// Reserve additional capacity
/// @param vec The vector to resize
/// @param additional Additional capacity to reserve
pub func<T>:vec_reserve = result(Vec<*T>@:vec, uint64:additional) {
    uint64:needed = vec->length + additional;
    if (needed <= vec->capacity) {
        pass(NIL);  // Already have enough capacity
    }

    // Allocate new buffer
    wild *T@:new_data = aria.alloc<*T>(needed);
    if (new_data == NULL) {
        fail(ERR);
    }

    // Copy existing elements
    loop(0, vec->length, 1) {
        new_data[$] = vec->data[$];
    }

    // Free old buffer
    if (vec->data != NULL) {
        aria.free(vec->data);
    }

    vec->data = new_data;
    vec->capacity = needed;
    pass(NIL);
};

/// Free the vector's memory
/// @param vec The vector to free
pub func<T>:vec_free = result(Vec<*T>@:vec) {
    if (vec->data != NULL) {
        aria.free(vec->data);
        vec->data = NULL;
    }
    vec->length = 0;
    vec->capacity = 0;
    pass(NIL);
};

// ============================================================================
// HashMap<K,V> - Hash Table
// ============================================================================

/// A hash table mapping keys to values
///
/// HashMap provides O(1) average case insertion, lookup, and deletion.
/// Uses open addressing with linear probing for collision resolution.
///
/// @example
/// ```aria
/// // Create hash map for int64 keys
/// HashMap<int64,int32>:scores = hashmap_new<int64,int32>();
/// hashmap_insert(&scores, 1, 95, hash_int64);
/// hashmap_insert(&scores, 2, 87, hash_int64);
/// 
/// // Lookup
/// result<int32>:score = hashmap_get(&scores, 1, hash_int64);
/// if (score.err == NULL) {
///     stdout.write(`Score: &{score.val}\n`);
/// }
/// 
/// // String keys example
/// HashMap<string,int32>:names = hashmap_new<string,int32>();
/// hashmap_insert(&names, "Alice", 95, hash_string);
/// hashmap_insert(&names, "Bob", 87, hash_string);
/// ```
pub struct HashMap<K,V> {
    wild HashEntry<K,V>@:entries;  // Array of entries
    uint64:length;                  // Number of entries
    uint64:capacity;                // Table capacity
}

/// Hash table entry
struct HashEntry<K,V> {
    *K:key;
    *V:value;
    bool:occupied;
}

/// Create a new empty hash map
pub func<K,V>:hashmap_new = HashMap<*K,*V>() {
    HashMap<*K,*V>:map = {
        entries: NULL,
        length: 0,
        capacity: 0
    };
    pass(map);
};

/// Generic hash functions for common types

/// Hash function for int64
pub func hash_int64 = uint64(int64:key) {
    // Multiplicative hash with good distribution
    uint64:h = key * 2654435761;
    pass(h);
};

/// Hash function for uint64
pub func hash_uint64 = uint64(uint64:key) {
    // Multiplicative hash
    uint64:h = key * 2654435761;
    pass(h);
};

/// Hash function for int32
pub func hash_int32 = uint64(int32:key) {
    uint64:extended = key;
    uint64:h = extended * 2654435761;
    pass(h);
};

/// Hash function for uint32
pub func hash_uint32 = uint64(uint32:key) {
    uint64:extended = key;
    uint64:h = extended * 2654435761;
    pass(h);
};

/// Hash function for string (FNV-1a)
pub func hash_string = uint64(string:key) {
    uint64:hash = 14695981039346656037;  // FNV offset basis
    uint64:prime = 1099511628211;        // FNV prime

    // Note: This assumes string has .length and indexable chars
    // Actual implementation depends on Aria's string representation
    loop(0, key.length, 1) {
        hash = hash ^ key[$];
        hash = hash * prime;
    }

    pass(hash);
};

/// Hash function pointer type - maps a key to uint64
pub type HashFunc<K> = func(uint64)(*K:key);

/// Insert or update a key-value pair
/// @param map The hash map
/// @param key The key
/// @param value The value
/// @param hash_func Function to hash the key (e.g., hash_int64, hash_string)
/// @return Result indicating success or allocation failure
pub func<K,V>:hashmap_insert = result(HashMap<*K,*V>@:map, *K:key, *V:value, HashFunc<*K>:hash_func) {
    // Check if we need to grow (load factor > 0.7)
    if (map->capacity == 0 || map->length * 10 >= map->capacity * 7) {
        // Double capacity (or start at 16)
        uint64:new_cap = is map->capacity == 0 : 16 : map->capacity * 2;

        // Allocate new entries array
        wild HashEntry<*K,*V>@:new_entries = aria.alloc<HashEntry<*K,*V>>(new_cap);
        if (new_entries == NULL) {
            fail(ERR);  // Allocation failed
        }

        // Initialize all entries as unoccupied
        loop(0, new_cap, 1) {
            new_entries[$].occupied = false;
        }

        // Rehash existing entries
        if (map->entries != NULL) {
            loop(0, map->capacity, 1) {
                if (map->entries[$].occupied) {
                    // Find new slot
                    uint64:hash = hash_func(map->entries[$].key);
                    uint64:idx = hash % new_cap;
                    while (new_entries[idx].occupied) {
                        idx = (idx + 1) % new_cap;
                    }
                    new_entries[idx].key = map->entries[$].key;
                    new_entries[idx].value = map->entries[$].value;
                    new_entries[idx].occupied = true;
                }
            }
            aria.free(map->entries);
        }

        map->entries = new_entries;
        map->capacity = new_cap;
    }

    // Find slot using linear probing
    uint64:hash = hash_func(key);
    uint64:idx = hash % map->capacity;
    uint64:start = idx;

    // Look for existing key or empty slot
    while (map->entries[idx].occupied) {
        if (map->entries[idx].key == key) {
            // Update existing entry
            map->entries[idx].value = value;
            pass(NIL);
        }
        idx = (idx + 1) % map->capacity;
        if (idx == start) {
            fail(ERR);  // Table is full (shouldn't happen with load factor check)
        }
    }

    // Insert new entry
    map->entries[idx].key = key;
    map->entries[idx].value = value;
    map->entries[idx].occupied = true;
    map->length = map->length + 1;

    pass(NIL);
};

/// Get value for a key
/// @param map The hash map
/// @param key The key to look up
/// @param hash_func Function to hash the key
/// @return The value if found, or ERR if not present
pub func<K,V>:hashmap_get = result<*V>(HashMap<*K,*V>@:map, *K:key, HashFunc<*K>:hash_func) {
    if (map->capacity == 0) {
        fail(ERR);  // Empty map
    }

    // Find slot using linear probing
    uint64:hash = hash_func(key);
    uint64:idx = hash % map->capacity;
    uint64:start = idx;

    // Search for key
    while (map->entries[idx].occupied) {
        if (map->entries[idx].key == key) {
            pass(map->entries[idx].value);
        }
        idx = (idx + 1) % map->capacity;
        if (idx == start) {
            fail(ERR);  // Wrapped around, key not found
        }
    }

    fail(ERR);  // Key not found
};

/// Remove a key-value pair
/// @param map The hash map
/// @param key The key to remove
/// @param hash_func Function to hash the key
/// @return Result indicating success
pub func<K,V>:hashmap_remove = result(HashMap<*K,*V>@:map, *K:key, HashFunc<*K>:hash_func) {
    if (map->capacity == 0) {
        fail(ERR);  // Empty map
    }

    // Find slot using linear probing
    uint64:hash = hash_func(key);
    uint64:idx = hash % map->capacity;
    uint64:start = idx;

    // Search for key
    while (map->entries[idx].occupied) {
        if (map->entries[idx].key == key) {
            // Found the key - remove it
            map->entries[idx].occupied = false;
            map->length = map->length - 1;

            // Rehash subsequent entries to fix probe chain
            uint64:next = (idx + 1) % map->capacity;
            while (map->entries[next].occupied) {
                // Save entry data
                *K:rehash_key = map->entries[next].key;
                *V:rehash_value = map->entries[next].value;

                // Clear entry
                map->entries[next].occupied = false;
                map->length = map->length - 1;

                // Re-insert (will find correct position)
                // Find new slot for this entry
                uint64:new_hash = hash_func(rehash_key);
                uint64:new_idx = new_hash % map->capacity;
                while (map->entries[new_idx].occupied) {
                    new_idx = (new_idx + 1) % map->capacity;
                }
                map->entries[new_idx].key = rehash_key;
                map->entries[new_idx].value = rehash_value;
                map->entries[new_idx].occupied = true;
                map->length = map->length + 1;

                next = (next + 1) % map->capacity;
            }

            pass(NIL);
        }
        idx = (idx + 1) % map->capacity;
        if (idx == start) {
            fail(ERR);  // Wrapped around, key not found
        }
    }

    fail(ERR);  // Key not found
};

/// Check if key exists
/// @param map The hash map
/// @param key The key to check
/// @param hash_func Function to hash the key
/// @return true if key exists, false otherwise
pub func<K,V>:hashmap_contains_key = bool(HashMap<*K,*V>@:map, *K:key, HashFunc<*K>:hash_func) {
    result<*V>:r = hashmap_get(map, key, hash_func);
    pass(r.err == NULL);
};

/// Get number of entries
/// @param map The hash map
/// @return Number of entries
pub func<K,V>:hashmap_len = uint64(HashMap<*K,*V>@:map) {
    pass(map->length);
};

/// Check if map is empty
/// @param map The hash map
/// @return true if empty, false otherwise
pub func<K,V>:hashmap_is_empty = bool(HashMap<*K,*V>@:map) {
    pass(map->length == 0);
};

/// Free the hash map's memory
/// @param map The hash map to free
pub func<K,V>:hashmap_free = result(HashMap<*K,*V>@:map) {
    if (map->entries != NULL) {
        aria.free(map->entries);
        map->entries = NULL;
    }
    map->length = 0;
    map->capacity = 0;
    pass(NIL);
};

