/// A doubly-linked list
///
/// LinkedList provides O(1) push/pop at both ends and O(n) indexing.
/// Useful when you need efficient insertion/removal at arbitrary positions.
///
/// @example
/// ```aria
/// LinkedList<string>:names = LinkedList::new();
/// names.push_back("Alice");
/// names.push_back("Bob");
/// names.push_front("Charlie");
/// // List: Charlie -> Alice -> Bob
/// ```
pub struct LinkedList<T> {
    wild Node<*T>@:head;
    wild Node<*T>@:tail;
    uint64:length;
}

/// Node in a linked list
struct Node<T> {
    *T:value;
    wild Node<*T>@:next;
    wild Node<*T>@:prev;
}

/// Create a new empty linked list
pub func<T>:linkedlist_new = LinkedList<*T>() {
    LinkedList<*T>:list = {
        head: NULL,
        tail: NULL,
        length: 0
    };
    pass(list);
};

/// Add element to the front
/// @param list The linked list
/// @param value The value to add
/// @return Result indicating success or allocation failure
pub func<T>:linkedlist_push_front = result(LinkedList<*T>@:list, *T:value) {
    // Allocate new node
    wild Node<*T>@:node = aria.alloc<Node<*T>>(1);
    if (node == NULL) {
        fail(ERR);
    }

    node->value = value;
    node->next = list->head;
    node->prev = NULL;

    if (list->head != NULL) {
        list->head->prev = node;
    }

    list->head = node;

    if (list->tail == NULL) {
        list->tail = node;
    }

    list->length = list->length + 1;
    pass(NIL);
};

/// Add element to the back
/// @param list The linked list
/// @param value The value to add
/// @return Result indicating success or allocation failure
pub func<T>:linkedlist_push_back = result(LinkedList<*T>@:list, *T:value) {
    // Allocate new node
    wild Node<*T>@:node = aria.alloc<Node<*T>>(1);
    if (node == NULL) {
        fail(ERR);
    }

    node->value = value;
    node->next = NULL;
    node->prev = list->tail;

    if (list->tail != NULL) {
        list->tail->next = node;
    }

    list->tail = node;

    if (list->head == NULL) {
        list->head = node;
    }

    list->length = list->length + 1;
    pass(NIL);
};

/// Remove and return element from the front
/// @param list The linked list
/// @return The value, or ERR if empty
pub func<T>:linkedlist_pop_front = result<*T>(LinkedList<*T>@:list) {
    if (list->head == NULL) {
        fail(ERR);  // Empty list
    }

    wild Node<*T>@:node = list->head;
    *T:value = node->value;

    list->head = node->next;
    if (list->head != NULL) {
        list->head->prev = NULL;
    } else {
        list->tail = NULL;
    }

    aria.free(node);
    list->length = list->length - 1;

    pass(value);
};

/// Remove and return element from the back
/// @param list The linked list
/// @return The value, or ERR if empty
pub func<T>:linkedlist_pop_back = result<*T>(LinkedList<*T>@:list) {
    if (list->tail == NULL) {
        fail(ERR);  // Empty list
    }

    wild Node<*T>@:node = list->tail;
    *T:value = node->value;

    list->tail = node->prev;
    if (list->tail != NULL) {
        list->tail->next = NULL;
    } else {
        list->head = NULL;
    }

    aria.free(node);
    list->length = list->length - 1;

    pass(value);
};

/// Get the number of elements
/// @param list The linked list
/// @return The number of elements
pub func<T>:linkedlist_len = uint64(LinkedList<*T>@:list) {
    pass(list->length);
};

/// Check if list is empty
/// @param list The linked list
/// @return true if empty, false otherwise
pub func<T>:linkedlist_is_empty = bool(LinkedList<*T>@:list) {
    pass(list->length == 0);
};

/// Free the linked list's memory
/// @param list The linked list to free
pub func<T>:linkedlist_free = result(LinkedList<*T>@:list) {
    wild Node<*T>@:current = list->head;

    while (current != NULL) {
        wild Node<*T>@:next = current->next;
        aria.free(current);
        current = next;
    }

    list->head = NULL;
    list->tail = NULL;
    list->length = 0;

    pass(NIL);
};

