pub func:quickselect_i32 = int32(int32->:arr, int32:low, int32:high, int32:k) {
    if (low == high) {
        return arr[low];
    }

    int32:pivot_index = quickselect_partition_i32(arr, low, high);

    if (k == pivot_index) {
        return arr[k];
    }

    if (k < pivot_index) {
        return quickselect_i32(arr, low, pivot_index - 1, k);
    }

    return quickselect_i32(arr, pivot_index + 1, high, k);
};

// Find median using quickselect
pub func:median_i32 = int32(int32->:arr, int32:len) {
    if (len == 0) {
        return 0;
    }

    int32:mid = len / 2;
    return quickselect_i32(arr, 0, len - 1, mid);
};

