enum:alloc_error = {
    out_of_memory = 1,      // System allocator returned NULL
    invalid_size = 2,       // Size is 0 or exceeds limits
    invalid_alignment = 3,  // Alignment not power of 2
    size_overflow = 4,      // size * count overflow
    unsupported = 5         // Operation not supported
}

/**
 * Get human-readable message for allocation error
 * 
 * Example:
 *   string:msg = alloc_error_message(alloc_error.out_of_memory);
 *   // msg == "Out of memory"
 */
func:alloc_error_message = string(error: alloc_error) {
    // Call runtime function
    wild byte@:raw_msg = @extern("aria_alloc_error_message", error);

    // Cast to string (assuming string is wild byte@)
    string:msg = @cast<string>(raw_msg);

    return msg;
}

