 * This is a specialized result type for wild pointer allocations.
 * The generic result<T, E> type will come later when the generics
 * parser is complete.
 * 
 * Memory layout (matches AriaAllocResult in C++):
 * - value: wild T@ (pointer, valid when error_code == 0)
 * - error_code: int32 (0 = success, >0 = error variant)
 * - requested_size: int64 (diagnostic info)
 * - requested_align: int64 (diagnostic info)
 */
struct:alloc_result<T> = {
    value: wild T@,
    error_code: int32,
    requested_size: int64,
    requested_align: int64
