/**
 * Check if result is Ok (success)
 * 
 * Example:
 *   alloc_result<int64>:res = alloc_result<int64>();
 *   if (res.is_ok()) {
 *       // Success path
 *   }
 */
func:is_ok<T> = bool(result: alloc_result<T>) {
    return result.error_code == 0;
}

/**
 * Check if result is Err (error)
 * 
 * Example:
 *   alloc_result<int64>:res = alloc_result<int64>();
 *   if (res.is_err()) {
 *       // Error path
 *   }
 */
func:is_err<T> = bool(result: alloc_result<T>) {
    return result.error_code != 0;
