// CRITICAL FIX 4: Replace abort() with panic handler that executes defer blocks
// The abort() was "extreme severity" - robot holding object, unwrap fails,
// instant death without defer unlock_actuators() → crushing force
//
// New behavior: Call runtime panic handler that:
// 1. Executes all defer blocks in current thread
// 2. Calls hardware safety callback (engage brakes)
// 3. For async: kills only faulting task, not entire process
// 4. Logs full context before controlled shutdown
//
// NOTE: For production deployment, consider banning unwrap() entirely via linter
// and forcing explicit error handling with is_ok()/is_err() checks
func:unwrap<T> = wild T@(result: alloc_result<T>) {
    if (result.error_code != 0) {
        // Record panic event for debugging statistics
        @extern("aria_telemetry_record_panic");
        aria_telemetry_record_panic("unwrap_error");

        // Call panic handler instead of abort()
        // This allows defer execution and safe shutdown
        @extern("aria_runtime_panic_unwrap");
        aria_runtime_panic_unwrap("Attempted to unwrap error result");
        // Never returns - but unlike abort(), executes cleanup
    }
    return result.value;
}

/**
 * Unwrap error (panics if Ok)
 * 
 * Example:
 *   alloc_result<int64>:res = alloc_result<int64>();
 *   if (res.is_err()) {
 *       alloc_error:err = res.unwrap_err();
