func:unwrap_err<T> = alloc_error(result: alloc_result<T>) {
    if (result.error_code == 0) {
        // Panic - attempted to unwrap_err on Ok result
        @extern("aria_runtime_panic_unwrap");
        aria_runtime_panic_unwrap("Attempted to unwrap_err on Ok result");
    }
    return @cast<alloc_error>(result.error_code);
