    @extern("aria_arena_get_stats", arena.handle, user_bytes, sys_bytes, blocks);
    pass(NIL);
}

/**
 * Get remaining capacity in current block
 * 
 * @param arena Arena to query
 * @return Bytes available before next block allocation
 * 
 * Useful for debugging allocation patterns.
 * 
 * Example:
 *   int64:remaining = remaining_capacity(my_arena);
 *   if (remaining < 1024) {
 *       // Next large allocation will trigger new block
 *   }
 */
func:remaining_capacity = int64(arena: arena@) {
    int64:remaining = @extern("aria_arena_remaining_capacity", arena.handle);
    return remaining;
}

// =============================================================================
// Documentation Notes
// =============================================================================

/**
 * USAGE PATTERNS:
 * 
 * 1. Single-Use Arena (Compiler Pass):
 *    arena_result:res = new_arena(65536);
 *    arena@:pass_arena = res.unwrap();
 *    defer destroy(pass_arena);
 *    
 *    // Allocate AST nodes
 *    // ... parse code ...
 *    
 *    // Arena automatically destroyed at scope exit
 * 
 * 2. Reusable Arena (Server Loop):
 *    arena_result:res = new_arena(32768);
 *    arena@:request_arena = res.unwrap();
 *    defer destroy(request_arena);
 *    
 *    loop {
 *        reset(request_arena);  // Zero malloc!
 *        
 *        // Handle request
 *        // All allocations freed on next reset
 *    }
 * 
 * 3. Growth-Limited Arena (Long-Running Service):
 *    arena_result:res = new_arena(8192);
 *    arena@:service_arena = res.unwrap();
 *    defer destroy(service_arena);
 *    
 *    loop {
 *        // Keep max 1MB, free excess
 *        reset_limit(service_arena, 1048576);
 *        
 *        // Process...
 *    }
 */

/**
 * PERFORMANCE CHARACTERISTICS:
 * 
 * Operation          | Time       | Comparison
 * -------------------+------------+------------------
 * arena_alloc (hot)  | ~2ns       | 10-25x faster than malloc
 * arena_alloc (cold) | ~100ns     | Same as malloc (rare)
 * reset (retain)     | ~2ns       | O(1) vs O(N) free
 * destroy            | O(blocks)  | Typically < 10 blocks
 * 
 * Memory Overhead:
 * - Per block: 24 bytes (header)
 * - Per allocation: 0 bytes (no metadata!)
 * - Alignment padding: Up to (align - 1) bytes
 * 
 * Optimal Use Cases:
 * - Compiler passes (many small AST nodes)
 * - Request handling (HTTP servers)
 * - Parsing (token/tree allocation)
 * - Temporary buffers (sort, filter, map)
 * 
 * Avoid When:
 * - Objects have destructors (use GC or manual free)
 * - Long-lived objects (use GC)
 * - Mixed lifetimes (some objects outlive others)
 */

/**
 * SAFETY CONSIDERATIONS:
 * 
 * 1. Use-After-Reset:
 *    alloc_result<int64>:res = arena_alloc<int64>(arena);
 *    wild int64->:ptr = res.unwrap();
 *    ptr@ = 42;
 *    
 *    reset(arena);  // ptr is now INVALID!
 *    
 *    int64:x = ptr@;  // ERROR: use-after-reset
 *    
 *    The borrow checker should treat reset() as a mutable borrow
 *    that invalidates all previous loans from the arena.
 * 
 * 2. No Destructors:
 *    Arenas do NOT run destructors. If you allocate objects with
 *    cleanup requirements (file handles, locks), you must manually
 *    clean them up before reset/destroy.
 * 
 * 3. Alignment Correctness:
 *    The arena respects @alignof(T) automatically. Mixed-type
 *    allocations are safe (no alignment violations).
 * 
 * 4. Thread Safety:
 *    Arenas are NOT thread-safe. Use one arena per thread, or
 *    wrap in a mutex for shared access.
 */

/**
 * COMPARISON: Arena vs Wild vs GC:
 * 
 *                  | Arena       | Wild        | GC
 * -----------------+-------------+-------------+------------
 * Alloc speed      | ~2ns        | ~30ns       | ~10ns
 * Free speed       | O(1) bulk   | ~30ns each  | Automatic
 * Memory overhead  | 0 per-alloc | 16-24 bytes | 8-16 bytes
 * Destructors      | Manual      | Automatic   | Automatic
 * Thread-safe      | No          | Yes         | Yes
 * Use case         | Phases      | C interop   | General
 * 
 * Use Arena when:
 * - Phase-oriented workload (clear reset points)
 * - High allocation frequency
 * - Objects don't need destructors
 * - Extreme performance required
 * 
 * Use Wild when:
 * - C library interop
 * - Manual control needed
 * - Individual deallocation required
 * 
 * Use GC when:
 * - General-purpose allocation
 * - Complex object graphs
 * - Automatic cleanup desired
 */

