bool:success = counter.compare_exchange(expected, desired);
// If counter == expected, set to desired and return true
// If counter != expected, set expected = counter and return false
// Uses SeqCst for both success and failure by default
unsafe { 
    bool:success = counter.compare_exchange_weak_acqrel(expected, desired);
    // Weak: May spuriously fail (retry in loop) - faster on some platforms
}

