int64:old = counter.fetch_add(delta);  // old_value = counter; counter += delta;
int64:old = counter.fetch_sub(delta);  // old_value = counter; counter -= delta;
int64:old = counter.fetch_and(mask);   // old_value = counter; counter &= mask;
int64:old = counter.fetch_or(mask);    // old_value = counter; counter |= mask;
int64:old = counter.fetch_xor(mask);   // old_value = counter; counter ^= mask;
// All return old value BEFORE modification
// All use SeqCst by default
unsafe { int64:old = counter.fetch_add_relaxed(delta); }  // Relaxed variant

