            *T:value = lock->data;  // Read data
            atomic_fence_acquire();  // Ensure read completes before seq2
            uint64:seq2 = lock->sequence.load_acquire();
            if (seq1 == seq2) { pass(value); }  // Sequence unchanged, consistent!
            // else retry - writer interfered
        }
    };
