func:enqueue<T> = result<NIL>(LockFreeQueue<*T>@:queue, *T:value) {
        Handle<Node<*T>>:new_node = arena.alloc(Node { value, next: NULL });
        loop {
            Handle<Node<*T>>:tail = queue->tail.load_acquire();
            Handle<Node<*T>>:next = tail->next.load_acquire();
            if (tail == queue->tail.load_acquire()) {  // Tail still valid?
                if (next == NULL) {  // Tail is last node?
                    if (tail->next.compare_exchange_weak_release(next, new_node)) {
                        queue->tail.compare_exchange_weak_release(tail, new_node);
                        pass(NIL);  // Success!
                    }
                } else {
                    queue->tail.compare_exchange_weak_release(tail, next);  // Help advance tail
                }
            }
        }
    };
}

