// TWISTED BALANCED BINARY (TBB) TYPES - SYMMETRIC INTEGERS WITH ERROR SENTINELS
// TBB types provide perfectly symmetric ranges by using the minimum two's complement value as ERR
// This eliminates asymmetry bugs (abs(-128), neg(-128)) and provides built-in error propagation
tbb8:safe_byte = 100;         // Valid range: [-127, +127]
tbb8:max_pos = 127;            // Maximum positive value
tbb8:max_neg = -127;           // Maximum negative value (symmetric!)
tbb8:error = ERR;              // Error sentinel (stored as -128/0x80)

// TBB ARITHMETIC - STICKY ERROR PROPAGATION
// Any operation with ERR input or overflow produces ERR
tbb8:a = 100;
tbb8:b = 50;
tbb8:res = a + b;           // 150 exceeds 127 → res = ERR
tbb8:chained = res + 10;    // ERR + 10 → ERR (sticky)

// TBB SAFETY - NO ASYMMETRY BUGS
tbb8:val = -127;
tbb8:negated = -val;           // 127 (works perfectly, symmetric range!)
tbb8:absolute = abs(val) ? ERR;      // 127 (always safe, no overflow)
// Compare to standard int8: abs(-128) would fail/wrap

// TBB USE CASES
// 1. Financial arithmetic - overflow detection without exceptions
// 2. Safe pointer arithmetic - invalid offsets become ERR
// 3. Audio/video processing - sample overflow → corruption detection
// 4. State machines - invalid state transitions → ERR
// 5. Branchless pipelines - check error once at end, not every operation

// FRACTION TYPES (frac) - EXACT RATIONAL ARITHMETIC
// Fraction types provide mathematically exact representation of rational numbers
// Built on TBB types, inheriting sticky error propagation and safety guarantees
// CRITICAL: No floating-point drift, no rounding errors, perfect determinism

// FRACTION STRUCTURE - MIXED NUMBER REPRESENTATION
// frac = Whole + Numerator/Denominator
// struct:frac<N> = { tbb<N>:whole; tbb<N>:num; tbb<N>:denom; }
// Value = whole + (num / denom)
// Example: 3 1/2 is stored as {whole: 3, num: 1, denom: 2}

// FRACTION CANONICAL FORM - STRICT INVARIANTS
// All frac values maintain these invariants (enforced by normalize()):
// 1. Denominator always positive (denom > 0)
// 2. Numerator non-negative when whole ≠ 0 (num ≥ 0)
// 3. Proper fraction (num < denom)
// 4. Reduced to lowest terms (gcd(num, denom) = 1)
// 5. Sign handling:
//    - If whole ≠ 0: Sign lives in whole, num stays positive
//    - If whole = 0: Sign lives in num (handles -1 < value < 0)

// FRACTION ARITHMETIC - EXACT OPERATIONS
// All operations use GCD reduction and maintain canonical form
// Overflow in intermediate calculations → ERR (sticky propagation)
// Division by zero → ERR
// Denominator overflow → ERR

// FRACTION LITERAL SYNTAX
// Primary: Struct initialization (explicit, unambiguous)
frac64:val1 = {1, 1, 2};            // Explicit: {whole, num, denom}

// FRACTION ERROR STATES (Sticky ERR Propagation)
// frac is ERR if any component is TBB ERR, or if denom = 0
frac64:zero_denom = {1, 1, 0};      // ERR (division by zero)
frac64:overflow = {ERR, 0, 1};      // ERR (whole is ERR)
frac64:err_result = zero_denom + {1, 0, 1};  // ERR (sticky propagation)

// FRACTION VS FLOAT - WHY EXACT RATIONALS MATTER
// JavaScript problem (floating-point drift):
//   0.1 + 0.2 = 0.30000000000000004  (WRONG!)
//   1/3 stored as 0.333333... (approximation)
//   (1/3) * 3 = 0.999999... ≈ 1 (needs epsilon comparison hacks)

// Aria solution (exact arithmetic):
frac64:third = {0, 1, 3};           // ACTUALLY 1/3, not approximation
frac64:result = third + third + third;  // EXACTLY {1, 0, 1} = 1
frac64:tenth = {0, 1, 10};          // EXACTLY 1/10
frac64:fifth = {0, 1, 5};           // EXACTLY 1/5  
frac64:exact_sum = tenth + fifth + fifth;  // EXACTLY 1/2 = {0, 1, 2}

// FRACTION USE CASES - WHERE EXACTNESS IS CRITICAL
// 1. Physics simulations - wave interference, phase offsets (no drift)
// 2. Financial calculations - compound interest, splits (no rounding errors)
// 3. Music theory - frequency ratios, harmonics (exact intervals)
// 4. Recipe scaling - 1/3 cup × 3 = exactly 1 cup (no accumulation)
// 5. Scientific ratios - stoichiometry, dilutions (precision required)
// 6. Legal contracts - profit shares, equity splits (must be exact)

// FRACTION SAFETY - ZERO-FAILURE GUARANTEE
// All failure modes collapse to deterministic ERR state:
// - Denominator overflow → ERR (not wraparound)
// - Division by zero → ERR (not crash/exception)
// - Component overflow → ERR (sticky propagation)
// - Invalid operations → ERR (no undefined behavior)
// Result: Safe for mission-critical systems (aerospace, medical, robotics)

// TWISTED FLOATING POINT (tfp) - DETERMINISTIC REAL NUMBERS
// Twisted Floating Point provides IEEE-free floating-point arithmetic
// Built from TBB exponent + TBB mantissa, eliminating IEEE 754 problems
// CRITICAL: No -0, no NaN ambiguity, cross-platform bit-exact determinism

// TFP STRUCTURE - TBB COMPONENT COMPOSITION
// tfp = Mantissa × 2^Exponent (both components are TBB types)
// tfp32: tbb16 exponent + tbb16 mantissa (32 bits total)
// tfp64: tbb16 exponent + tbb48 mantissa (64 bits total)
// Sign lives in mantissa (2's complement), not separate bit

// WHY TFP EXISTS - IEEE 754 PROBLEMS SOLVED
// IEEE Problem 1: +0 and -0 are different (breaks zero neutrality)
//   - 1.0 / +0.0 = +Inf, but 1.0 / -0.0 = -Inf (non-deterministic)
//   - Phase calculations can flip sign due to rounding artifacts
// IEEE Problem 2: Multiple NaN states (qNaN, sNaN, payload bits)
//   - NaN propagates silently through calculations (no error detection)
//   - Can't distinguish "sqrt(-1)" NaN from "0/0" NaN
// IEEE Problem 3: Platform-dependent rounding
//   - x86 FPU vs ARM NEON produce different bit patterns
//   - Same code, different results on different CPUs

// TFP Solution: Twisted Architecture
// 1. UNIQUE ZERO: Only one zero (0x0000000000000000), no +0/-0
// 2. UNIFIED ERR: All errors collapse to single ERR sentinel
// 3. SOFTWARE IMPLEMENTATION: Bit-exact across all platforms
// 4. STICKY ERROR PROPAGATION: ERR + anything = ERR

// TFP ARITHMETIC - DETERMINISTIC OPERATIONS
// All operations implemented in software (no hardware FPU)
// Ensures identical results on x86, ARM, RISC-V, etc.
tfp64:a = 1.5tf;
tfp64:b = 2.7tf;
tfp64:sum = a + b;                    // 4.2tf (bit-exact)
tfp64:product = a * b;                // 4.05tf (bit-exact)
tfp64:quotient = a / b;               // ~0.555556tf (bit-exact)

// TFP ERROR STATES (Sticky ERR Propagation)
// tfp is ERR if exponent is TBB ERR OR mantissa is TBB ERR
tfp64:div_by_zero = 1.0tf / 0.0tf;    // ERR (not Inf)
tfp64:sqrt_neg = sqrt(-1.0tf);        // ERR (not NaN)
tfp64:overflow = 1.0e308tf * 1.0e308tf; // ERR (not Inf)
tfp64:err_prop = error + 5.0tf;       // ERR (sticky propagation)

// TFP VS IEEE 754 - SAFETY COMPARISON
// IEEE 754 problem (non-determinism):
//   float x = 0.1f + 0.2f;  // Might be 0.30000001 on x86, 0.29999998 on ARM
//   if (x == 0.3f) { }      // Platform-dependent branch!
//   sqrt(-1.0) = NaN        // Silent corruption, keeps calculating
//   1.0 / 0.0 = Inf         // Spreads through calculation as "valid" number

// TFP PRECISION TRADE-OFFS
// tfp64: 48-bit mantissa (vs IEEE double's 53-bit)
//   - 5 fewer bits of precision (~15 decimal digits vs 16)
//   - Trade-off: Determinism and safety over raw precision
//   - Rationale: Rounding error drift often exceeds last 5 bits anyway
// tfp32: 16-bit mantissa (vs IEEE float's 24-bit)
//   - Lower precision, but deterministic and safe

// TFP PERFORMANCE CHARACTERISTICS
// Speed: ~10-50x slower than hardware IEEE float (software implementation)
// Safety: 100% deterministic, no silent failures
// Use case decision:
//   - Need speed, can tolerate platform variance → use flt32/flt64 (IEEE)
//   - Need safety, determinism, exact reproducibility → use tfp32/tfp64

// TFP USE CASES - WHERE DETERMINISM MATTERS
// 1. Physics simulations - wave interference, particle systems (no drift)
// 2. Financial calculations - compound interest with exact reproducibility
// 3. Scientific computing - deterministic results for peer review
// 4. Game replays - exact state reproduction across platforms
// 5. Distributed systems - consensus on floating-point calculations
// 6. AGI/AI safety - cognitive models must be deterministic
// 7. Mission-critical - aerospace, medical devices, robotics

// TFP CROSS-PLATFORM GUARANTEE
// Same source code produces identical bit patterns on:
//   - x86-64 (Intel/AMD)
//   - ARM64 (Apple Silicon, mobile)
//   - RISC-V
//   - Any future architecture
// Verification: Hash output of tfp calculation = same on all platforms

// TFP MATH LIBRARY (Deterministic Transcendentals)
// All math functions implemented via Taylor series (software)
// Guarantees bit-exact results across platforms
tfp64:angle = 1.57079632679tf;        // π/2
tfp64:sine = sin(angle);              // Exactly 1.0tf (via Taylor series)
tfp64:cosine = cos(0.0tf);            // Exactly 1.0tf (via Taylor series)
tfp64:root = sqrt(4.0tf);             // Exactly 2.0tf
tfp64:invalid = sqrt(-1.0tf);         // ERR (domain error)

// TFP ERROR PROPAGATION EXAMPLE (9D Toroidal Memory)
// In physics simulation, sensor failure should halt calculation, not corrupt
tfp64:sensor1 = readSensor(1);        // Returns tfp64
tfp64:sensor2 = readSensor(2);        // Might return ERR (sensor offline)
tfp64:combined = sensor1 + sensor2;   // ERR if either is ERR
tfp64:distance = sqrt(combined);      // ERR propagates (not NaN)
if (distance == ERR) {
    halt_actuator();                  // Safe shutdown, no erratic behavior
}

// TFP SAFETY - ZERO-FAILURE GUARANTEE
// All failure modes collapse to deterministic ERR state:
// - Division by zero → ERR (not Inf)
// - Domain errors (sqrt(-1)) → ERR (not NaN)
// - Overflow/underflow → ERR (not Inf/denormal)
// - Component ERR → whole value ERR (sticky propagation)
// - Invalid operations → ERR (no undefined behavior)
// Result: Safe for mission-critical systems where failure = lives at risk

// TFP TYPES BY WIDTH
tfp32:fast = 1.5tf;                   // 32-bit, lower precision
tfp64:standard = 3.14159265tf;        // 64-bit, standard precision

