func<T>:filter = *T[](*T[]:arr, int64:len, (bool)(*T):predicate) {
    *T[len]:output;
    int64:count = 0;
    for (int64:i = 0; i < len; i++) {
        if (predicate(arr[i])) {
            output[count] = arr[i];
            count = count + 1;
        }
    }
    pass(output);  // Note: actual size is 'count', not 'len'
};

